import { useState } from "react";

import axios from "axios";

export default function Register() {

  const [form, setForm] = useState({
    role: "customer"
  });

  const register = async () => {

    try {

      const data = { ...form };

      if (data.role === "labour") {

        data.skills = data.skills
          .split(",")
          .map(skill => skill.trim());
      }

      const res = await axios.post(
        "http://localhost:5000/api/auth/register",
        data
      );

      localStorage.setItem(
        "user",
        JSON.stringify(res.data)
      );

      alert("Registration Successful");

      if (data.role === "customer") {

        window.location = "/customer";

      } else {

        window.location = "/labour";
      }

    } catch (err) {

      alert(
        err.response?.data?.message ||
        "Registration Failed"
      );
    }
  };

  return (

    <div style={styles.page}>

      <div style={styles.card}>

        <h1 style={styles.heading}>
          Register
        </h1>

        <select
          style={styles.input}
          onChange={(e) =>
            setForm({
              ...form,
              role: e.target.value
            })
          }
        >

          <option value="customer">
            Customer
          </option>

          <option value="labour">
            Labour
          </option>

        </select>

        <input
          style={styles.input}
          placeholder="Name"
          onChange={(e) =>
            setForm({
              ...form,
              name: e.target.value
            })
          }
        />

        <input
          style={styles.input}
          placeholder="Email"
          onChange={(e) =>
            setForm({
              ...form,
              email: e.target.value
            })
          }
        />

        <input
          type="password"
          style={styles.input}
          placeholder="Password"
          onChange={(e) =>
            setForm({
              ...form,
              password: e.target.value
            })
          }
        />

        {form.role === "labour" && (

          <>
            <input
              style={styles.input}
              placeholder="Skills (comma separated)"
              onChange={(e) =>
                setForm({
                  ...form,
                  skills: e.target.value
                })
              }
            />

            <input
              style={styles.input}
              placeholder="Base Price"
              onChange={(e) =>
                setForm({
                  ...form,
                  price: e.target.value
                })
              }
            />
          </>
        )}

        <button
          style={styles.btn}
          onClick={register}
        >
          Register
        </button>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f5f7fb",
    display: "flex",
    justifyContent: "center",
    alignItems: "center"
  },

  card: {
    width: "400px",
    background: "white",
    padding: "35px",
    borderRadius: "18px",
    boxShadow: "0 4px 15px rgba(0,0,0,0.06)"
  },

  heading: {
    marginBottom: "25px"
  },

  input: {
    width: "100%",
    padding: "14px",
    marginBottom: "15px",
    borderRadius: "8px",
    border: "1px solid #ddd"
  },

  btn: {
    width: "100%",
    padding: "14px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
  }

};
